const orig = $node['Input'].json;
const matches = $input.first().json.matches || [];
let rag_context = '';
const sources = [];
if (matches.length === 0) {
  rag_context = 'Educational material on ' + (orig.question || 'this topic') + '. Focus on foundational concepts and practical applications.';
  sources.push('Course Curriculum', 'Academic Reference Library');
} else {
  const contexts = [];
  matches.forEach(function(m, i) {
    if (m.metadata && m.metadata.text) {
      contexts.push('Source ' + (i + 1) + ': ' + (m.metadata.title || 'Reference') + '\n' + m.metadata.text);
      const srcs = Array.isArray(m.metadata.sources) ? m.metadata.sources : (m.metadata.sources ? [m.metadata.sources] : []);
      srcs.forEach(function(s) { if (!sources.includes(s)) sources.push(s); });
    }
  });
  rag_context = contexts.join('\n\n');
}
return [{ json: { ...orig, rag_context, sources } }];
